+  id: number;
+  doc_type: DocumentType;
+  title: string;
+  version_label: string;
+  body: string;
+  state: DocumentState;
+  effective_date: string | null;
+  next_review_date: string | null;
+  source_id: string | null;
+  created_at: string;
+}
+
+const DOCUMENT_ENTITY = 'document_version';
+const DOCUMENT_TYPES: DocumentType[] = ['tokushoho', 'terms', 'privacy', 'contract_template', 'license', 'other'];
+const DOCUMENT_STATES: DocumentState[] = ['draft', 'published', 'archived'];
+
+export function listDocumentVersions(db: DB): DocumentVersion[] {
+  const rows = db
+    .prepare('SELECT * FROM document_versions ORDER BY doc_type ASC, created_at DESC, id DESC')
+    .all() as DocumentVersionRow[];
+  return rows.map(mapDocumentVersion);
+}
+
+export function listDocumentVersionsByType(db: DB, docType: DocumentType): DocumentVersion[] {
+  assertDocumentType(docType);
+  const rows = db
+    .prepare('SELECT * FROM document_versions WHERE doc_type = ? ORDER BY created_at DESC, id DESC')
+    .all(docType) as DocumentVersionRow[];
+  return rows.map(mapDocumentVersion);
+}
+
+export function getDocumentRevisionHistory(db: DB, docType: DocumentType): DocumentVersion[] {
+  return listDocumentVersionsByType(db, docType);
+}
+
+export function getDocumentVersion(db: DB, id: number): DocumentVersion | null {
+  const row = db.prepare('SELECT * FROM document_versions WHERE id = ?').get(id) as DocumentVersionRow | undefined;
+  return row ? mapDocumentVersion(row) : null;
+}
+
+export function createDocumentVersion(
+  db: DB,
+  input: CreateDocumentVersionInput,
+  actor = 'local_user',
+): DocumentVersion {
+  const payload = normalizeCreate(input);
+  return db.transaction(() => {
+    if (payload.state === 'published') archivePublishedForType(db, payload.docType);
+    const result = db
+      .prepare(
+        `INSERT INTO document_versions
+          (doc_type, title, version_label, body, state, effective_date, next_review_date, source_id)
+         VALUES
+          (@docType, @title, @versionLabel, @body, @state, @effectiveDate, @nextReviewDate, @sourceId)`,
+      )
+      .run(payload);
+    const created = getDocumentVersionOrThrow(db, Number(result.lastInsertRowid));
+    writeAudit(db, { actor, action: 'create', entityType: DOCUMENT_ENTITY, entityId: created.id, after: created });
+    return created;
+  })();
+}
+
+export function updateDocumentVersion(
+  db: DB,
+  id: number,
+  input: UpdateDocumentVersionInput,
+  actor = 'local_user',
+): DocumentVersion | null {
+  const before = getDocumentVersion(db, id);
+  if (!before) return null;
+  const next = { ...before, ...normalizeUpdate(input) };
+  return db.transaction(() => {
+    if (next.state === 'published') archivePublishedForType(db, next.docType, id);
+    db.prepare(
+      `UPDATE document_versions SET
+         doc_type = @docType,
+         title = @title,
+         version_label = @versionLabel,
+         body = @body,
+         state = @state,
+         effective_date = @effectiveDate,
+         next_review_date = @nextReviewDate,
+         source_id = @sourceId
+       WHERE id = @id`,
+    ).run({
+      id,
+      docType: next.docType,
+      title: next.title,
+      versionLabel: next.versionLabel,
+      body: next.body,
+      state: next.state,
+      effectiveDate: next.effectiveDate,
+      nextReviewDate: next.nextReviewDate,
+      sourceId: next.sourceId,
+    });
+    const after = getDocumentVersionOrThrow(db, id);
+    writeAudit(db, { actor, action: 'update', entityType: DOCUMENT_ENTITY, entityId: id, before, after });
+    return after;
+  })();
+}
+
+export function publishDocumentVersion(db: DB, id: number, actor = 'local_user'): DocumentVersion | null {
+  const before = getDocumentVersion(db, id);
+  if (!before) return null;
+  if (before.state === 'published') return before;
+
+  return db.transaction(() => {
+    const archived = archivePublishedForType(db, before.docType, id);
+    db.prepare("UPDATE document_versions SET state = 'published' WHERE id = ?").run(id);
+    const after = getDocumentVersionOrThrow(db, id);
+    writeAudit(db, {
+      actor,
+      action: 'publish',
+      entityType: DOCUMENT_ENTITY,
+      entityId: id,
+      before: { target: before, archived },
+      after,
+    });
+    return after;
+  })();
+}
+
+export function deleteDocumentVersion(db: DB, id: number, actor = 'local_user'): boolean {
+  const before = getDocumentVersion(db, id);
+  if (!before) return false;
+  db.transaction(() => {
+    writeAudit(db, { actor, action: 'delete', entityType: DOCUMENT_ENTITY, entityId: id, before });
+    db.prepare('DELETE FROM document_versions WHERE id = ?').run(id);
+  })();
+  return true;
+}
+
+function archivePublishedForType(db: DB, docType: DocumentType, exceptId?: number): DocumentVersion[] {
+  const published = db
+    .prepare(
+      `SELECT * FROM document_versions
+       WHERE doc_type = ? AND state = 'published' AND (? IS NULL OR id <> ?)
+       ORDER BY id ASC`,
+    )
+    .all(docType, exceptId ?? null, exceptId ?? null) as DocumentVersionRow[];
+  if (published.length === 0) return [];
+
+  db.prepare(
+    `UPDATE document_versions
+     SET state = 'archived'
+     WHERE doc_type = ? AND state = 'published' AND (? IS NULL OR id <> ?)`,
+  ).run(docType, exceptId ?? null, exceptId ?? null);
+  return published.map(mapDocumentVersion);
+}
+
+function getDocumentVersionOrThrow(db: DB, id: number): DocumentVersion {
+  const document = getDocumentVersion(db, id);
+  if (!document) throw new Error(`document version not found: ${id}`);
+  return document;
+}
+
+function normalizeCreate(input: CreateDocumentVersionInput): Omit<DocumentVersion, 'id' | 'createdAt'> {
+  const docType = parseDocumentType(input.docType);
+  return {
+    docType,
+    title: requireText(input.title, 'title'),
+    versionLabel: requireText(input.versionLabel, 'versionLabel'),
+    body: requireText(input.body, 'body'),
+    state: input.state == null ? 'draft' : parseDocumentState(input.state),
+    effectiveDate: nullableText(input.effectiveDate),
+    nextReviewDate: nullableText(input.nextReviewDate),
+    sourceId: nullableText(input.sourceId),
+  };
+}
+
+function normalizeUpdate(input: UpdateDocumentVersionInput): Partial<Omit<DocumentVersion, 'id' | 'createdAt'>> {
+  const next: Partial<Omit<DocumentVersion, 'id' | 'createdAt'>> = {};
+  if (input.docType !== undefined) next.docType = parseDocumentType(input.docType);
+  if (input.title !== undefined) next.title = requireText(input.title, 'title');
+  if (input.versionLabel !== undefined) next.versionLabel = requireText(input.versionLabel, 'versionLabel');
+  if (input.body !== undefined) next.body = requireText(input.body, 'body');
+  if (input.state !== undefined) next.state = input.state == null ? 'draft' : parseDocumentState(input.state);
+  if (input.effectiveDate !== undefined) next.effectiveDate = nullableText(input.effectiveDate);
+  if (input.nextReviewDate !== undefined) next.nextReviewDate = nullableText(input.nextReviewDate);
+  if (input.sourceId !== undefined) next.sourceId = nullableText(input.sourceId);
+  return next;
+}
+
+function mapDocumentVersion(row: DocumentVersionRow): DocumentVersion {
+  return {
+    id: row.id,
+    docType: row.doc_type,
+    title: row.title,
+    versionLabel: row.version_label,
+    body: row.body,
+    state: row.state,
+    effectiveDate: row.effective_date,
+    nextReviewDate: row.next_review_date,
+    sourceId: row.source_id,
+    createdAt: row.created_at,
+  };
+}
+
+function parseDocumentType(value: unknown): DocumentType {
+  if (typeof value !== 'string' || !DOCUMENT_TYPES.includes(value as DocumentType)) {
+    throw new Error(`docType must be one of: ${DOCUMENT_TYPES.join(', ')}`);
+  }
+  return value as DocumentType;
+}
+
+function parseDocumentState(value: unknown): DocumentState {
+  if (typeof value !== 'string' || !DOCUMENT_STATES.includes(value as DocumentState)) {
+    throw new Error(`state must be one of: ${DOCUMENT_STATES.join(', ')}`);
+  }
+  return value as DocumentState;
+}
+
+function assertDocumentType(value: DocumentType): void {
+  parseDocumentType(value);
+}
+
+function requireText(value: string | null | undefined, field: string): string {
+  const text = nullableText(value);
+  if (!text) throw new Error(`${field} is required`);
+  return text;
+}
+
+function nullableText(value: string | null | undefined): string | null {
+  if (value == null) return null;
+  const text = value.trim();
+  return text.length > 0 ? text : null;
+}
diff --git a/packages/core/test/documents.test.ts b/packages/core/test/documents.test.ts
new file mode 100755
index 0000000000000000000000000000000000000000..53eea8382a0a6382d755de6ce4574664de73fbcf
--- /dev/null
+++ b/packages/core/test/documents.test.ts
@@ -0,0 +1,160 @@
+import { describe, expect, it } from 'vitest';
+import { bootstrap } from '../src/db/bootstrap.js';
+import { seedLegalTemplates } from '../src/seed/legal.js';
+import {
+  createDocumentVersion,
+  deleteDocumentVersion,
+  getDocumentRevisionHistory,
+  getDocumentVersion,
+  listDocumentVersions,
+  listDocumentVersionsByType,
+  publishDocumentVersion,
+  updateDocumentVersion,
+} from '../src/services/documents.js';
+
+describe('documents service', () => {
+  it('creates, lists, gets, updates, and deletes document versions with audit logs', () => {
+    const db = bootstrap({ filename: ':memory:' });
+
+    const created = createDocumentVersion(db, {
+      docType: 'terms',
+      title: '利用規約',
+      versionLabel: 'v1',
+      body: '初版本文',
+      effectiveDate: '2026-07-01',
+      nextReviewDate: '2027-01-01',
+      sourceId: 'S6',
+    });
+    expect(created).toMatchObject({
+      id: expect.any(Number),
+      docType: 'terms',
+      title: '利用規約',
+      versionLabel: 'v1',
+      body: '初版本文',
+      state: 'draft',
+      effectiveDate: '2026-07-01',
+      nextReviewDate: '2027-01-01',
+      sourceId: 'S6',
+      createdAt: expect.any(String),
+    });
+    expect(listDocumentVersions(db)).toHaveLength(1);
+    expect(getDocumentVersion(db, created.id)?.versionLabel).toBe('v1');
+
+    const updated = updateDocumentVersion(db, created.id, {
+      versionLabel: 'v1.1',
+      body: '改定本文',
+      nextReviewDate: null,
+    });
+    expect(updated).toMatchObject({
+      id: created.id,
+      versionLabel: 'v1.1',
+      body: '改定本文',
+      nextReviewDate: null,
+    });
+
+    expect(deleteDocumentVersion(db, created.id)).toBe(true);
+    expect(getDocumentVersion(db, created.id)).toBeNull();
+
+    const audits = db
+      .prepare(
+        `SELECT action, entity_type, entity_id, before_json, after_json
+         FROM audit_logs
+         WHERE entity_type = ?
+         ORDER BY id ASC`,
+      )
+      .all('document_version') as Array<{
+      action: string;
+      entity_type: string;
+      entity_id: string;
+      before_json: string | null;
+      after_json: string | null;
+    }>;
+    expect(audits.map((row) => row.action)).toEqual(['create', 'update', 'delete']);
+    expect(audits.every((row) => row.entity_id === String(created.id))).toBe(true);
+    expect(JSON.parse(audits[0]?.after_json ?? '{}')).toMatchObject({ versionLabel: 'v1' });
+    expect(JSON.parse(audits[1]?.before_json ?? '{}')).toMatchObject({ body: '初版本文' });
+    expect(JSON.parse(audits[1]?.after_json ?? '{}')).toMatchObject({ body: '改定本文' });
+    expect(JSON.parse(audits[2]?.before_json ?? '{}')).toMatchObject({ versionLabel: 'v1.1' });
+
+    db.close();
+  });
+
+  it('publishes one version per doc type and archives the previous published version', () => {
+    const db = bootstrap({ filename: ':memory:' });
+    const v1 = createDocumentVersion(db, {
+      docType: 'privacy',
+      title: 'プライバシーポリシー',
+      versionLabel: 'v1',
+      body: '初版',
+      state: 'published',
+      effectiveDate: '2026-07-01',
+      sourceId: 'S9',
+    });
+    const v2 = createDocumentVersion(db, {
+      docType: 'privacy',
+      title: 'プライバシーポリシー',
+      versionLabel: 'v2',
+      body: '改定版',
+      effectiveDate: '2026-10-01',
+      sourceId: 'S9',
+    });
+
+    const published = publishDocumentVersion(db, v2.id);
+    expect(published).toMatchObject({ id: v2.id, state: 'published' });
+    expect(getDocumentVersion(db, v1.id)?.state).toBe('archived');
+
+    const privacyVersions = listDocumentVersionsByType(db, 'privacy');
+    expect(privacyVersions.filter((version) => version.state === 'published')).toHaveLength(1);
+    expect(privacyVersions.filter((version) => version.state === 'archived')).toHaveLength(1);
+    expect(getDocumentRevisionHistory(db, 'privacy').map((version) => version.versionLabel)).toEqual(['v2', 'v1']);
+
+    const actions = db
+      .prepare('SELECT action FROM audit_logs WHERE entity_type = ? ORDER BY id ASC')
+      .all('document_version')
+      .map((row) => (row as { action: string }).action);
+    expect(actions).toEqual(['create', 'create', 'publish']);
+
+    db.close();
+  });
+
+  it('rejects invalid type and state values', () => {
+    const db = bootstrap({ filename: ':memory:' });
+
+    expect(() =>
+      createDocumentVersion(db, {
+        docType: 'bad' as never,
+        title: '不正',
+        versionLabel: 'v1',
+        body: 'body',
+      }),
+    ).toThrow(/docType must be one of/);
+
+    expect(() =>
+      createDocumentVersion(db, {
+        docType: 'license',
+        title: 'ライセンス',
+        versionLabel: 'v1',
+        body: 'body',
+        state: 'active' as never,
+      }),
+    ).toThrow(/state must be one of/);
+
+    db.close();
+  });
+
+  it('seeds legal templates idempotently', () => {
+    const db = bootstrap({ filename: ':memory:' });
+
+    expect(seedLegalTemplates(db)).toEqual({ inserted: 5, updated: 0, unchanged: 0, total: 5 });
+    expect(seedLegalTemplates(db)).toEqual({ inserted: 0, updated: 0, unchanged: 5, total: 5 });
+    expect(listDocumentVersionsByType(db, 'tokushoho')[0]).toMatchObject({
+      title: '特定商取引法に基づく表記',
+      versionLabel: 'initial-template',
+      state: 'draft',
+      sourceId: 'S6',
+    });
+    expect(listDocumentVersions(db)).toHaveLength(5);
+
+    db.close();
+  });
+});
diff --git a/packages/server/src/routes/documents.ts b/packages/server/src/routes/documents.ts
new file mode 100755
index 0000000000000000000000000000000000000000..ace175d3e8057e7ac345630ee0d6c9417e47ac8b
--- /dev/null
+++ b/packages/server/src/routes/documents.ts
@@ -0,0 +1,352 @@
+import type { FastifyInstance } from 'fastify';
+import { writeAudit, type DB } from '@free-worker/core';
+
+type DocumentType = 'tokushoho' | 'terms' | 'privacy' | 'contract_template' | 'license' | 'other';
+type DocumentState = 'draft' | 'published' | 'archived';
+
+interface DocumentVersion {
+  id: number;
+  docType: DocumentType;
+  title: string;
+  versionLabel: string;
+  body: string;
+  state: DocumentState;
+  effectiveDate: string | null;
+  nextReviewDate: string | null;
+  sourceId: string | null;
+  createdAt: string;
+}
+
+interface DocumentPayload {
+  docType?: unknown;
+  title?: unknown;
+  versionLabel?: unknown;
+  body?: unknown;
+  state?: unknown;
+  effectiveDate?: unknown;
+  nextReviewDate?: unknown;
+  sourceId?: unknown;
+}
+
+interface DocumentRow {
+  id: number;
+  doc_type: DocumentType;
+  title: string;
+  version_label: string;
+  body: string;
+  state: DocumentState;
+  effective_date: string | null;
+  next_review_date: string | null;
+  source_id: string | null;
+  created_at: string;
+}
+
+interface IdParams {
+  id: string;
+}
+
+interface HistoryParams {
+  docType: string;
+}
+
+interface ListQuery {
+  docType?: string;
+}
+
+const DOCUMENT_TYPES: DocumentType[] = ['tokushoho', 'terms', 'privacy', 'contract_template', 'license', 'other'];
+const DOCUMENT_STATES: DocumentState[] = ['draft', 'published', 'archived'];
+const DOCUMENT_ENTITY = 'document_version';
+
+export async function documentRoutes(app: FastifyInstance): Promise<void> {
+  app.get<{ Querystring: ListQuery }>('/api/documents', async (req, reply) => {
+    if (req.query.docType !== undefined) {
+      const docType = parseDocumentTypeOrNull(req.query.docType);
+      if (!docType) {
+        reply.code(400);
+        return { error: 'invalid_doc_type' };
+      }
+      return listDocumentsByType(app.db, docType);
+    }
+    return listDocuments(app.db);
+  });
+
+  app.get<{ Params: HistoryParams }>('/api/documents/history/:docType', async (req, reply) => {
+    const docType = parseDocumentTypeOrNull(req.params.docType);
+    if (!docType) {
+      reply.code(400);
+      return { error: 'invalid_doc_type' };
+    }
+    return listDocumentsByType(app.db, docType);
+  });
+
+  app.get<{ Params: IdParams }>('/api/documents/:id', async (req, reply) => {
+    const id = parseId(req.params.id);
+    if (id == null) {
+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    const document = getDocument(app.db, id);
+    if (!document) {
+      reply.code(404);
+      return { error: 'not_found' };
+    }
+    return document;
+  });
+
+  app.post<{ Body: DocumentPayload }>('/api/documents', async (req, reply) => {
+    try {
+      const created = createDocument(app.db, req.body ?? {});
+      reply.code(201);
+      return created;
+    } catch (error) {
+      reply.code(400);
+      return invalidPayload(error);
+    }
+  });
+
+  app.put<{ Body: DocumentPayload; Params: IdParams }>('/api/documents/:id', async (req, reply) => {
+    const id = parseId(req.params.id);
+    if (id == null) {
+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    if (!getDocument(app.db, id)) {
+      reply.code(404);
+      return { error: 'not_found' };
+    }
+    try {
+      return updateDocument(app.db, id, req.body ?? {});
+    } catch (error) {
+      reply.code(400);
+      return invalidPayload(error);
+    }
+  });
+
+  app.post<{ Params: IdParams }>('/api/documents/:id/publish', async (req, reply) => {
+    const id = parseId(req.params.id);
+    if (id == null) {
+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    const published = publishDocument(app.db, id);
+    if (!published) {
+      reply.code(404);
+      return { error: 'not_found' };
+    }
+    return published;
+  });
+
+  app.delete<{ Params: IdParams }>('/api/documents/:id', async (req, reply) => {
+    const id = parseId(req.params.id);
+    if (id == null) {
+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    const before = getDocument(app.db, id);
+    if (!before) {
+      reply.code(404);
+      return { error: 'not_found' };
+    }
+    app.db.transaction(() => {
+      writeAudit(app.db, { action: 'delete', entityType: DOCUMENT_ENTITY, entityId: id, before });
+      app.db.prepare('DELETE FROM document_versions WHERE id = ?').run(id);
+    })();
+    reply.code(204);
+    return undefined;
+  });
+}
+
+function listDocuments(db: DB): DocumentVersion[] {
+  const rows = db
+    .prepare('SELECT * FROM document_versions ORDER BY doc_type ASC, created_at DESC, id DESC')
+    .all() as DocumentRow[];
+  return rows.map(mapDocument);
+}
+
+function listDocumentsByType(db: DB, docType: DocumentType): DocumentVersion[] {
+  const rows = db
+    .prepare('SELECT * FROM document_versions WHERE doc_type = ? ORDER BY created_at DESC, id DESC')
+    .all(docType) as DocumentRow[];
+  return rows.map(mapDocument);
+}
+
+function getDocument(db: DB, id: number): DocumentVersion | null {
+  const row = db.prepare('SELECT * FROM document_versions WHERE id = ?').get(id) as DocumentRow | undefined;
+  return row ? mapDocument(row) : null;
+}
+
+function getDocumentOrThrow(db: DB, id: number): DocumentVersion {
+  const document = getDocument(db, id);
+  if (!document) throw new Error(`document version not found: ${id}`);
+  return document;
+}
+
+function createDocument(db: DB, body: DocumentPayload): DocumentVersion {
+  const payload = normalizeCreate(body);
+  return db.transaction(() => {
+    if (payload.state === 'published') archivePublishedForType(db, payload.docType);
+    const result = db
+      .prepare(
+        `INSERT INTO document_versions
+          (doc_type, title, version_label, body, state, effective_date, next_review_date, source_id)
+         VALUES
+          (@docType, @title, @versionLabel, @body, @state, @effectiveDate, @nextReviewDate, @sourceId)`,
+      )
+      .run(payload);
+    const created = getDocumentOrThrow(db, Number(result.lastInsertRowid));
+    writeAudit(db, { action: 'create', entityType: DOCUMENT_ENTITY, entityId: created.id, after: created });
+    return created;
+  })();
+}
+
+function updateDocument(db: DB, id: number, body: DocumentPayload): DocumentVersion {
+  const before = getDocumentOrThrow(db, id);
+  const next = { ...before, ...normalizeUpdate(body) };
+  return db.transaction(() => {
+    if (next.state === 'published') archivePublishedForType(db, next.docType, id);
+    db.prepare(
+      `UPDATE document_versions SET
+         doc_type = @docType,
+         title = @title,
+         version_label = @versionLabel,
+         body = @body,
+         state = @state,
+         effective_date = @effectiveDate,
+         next_review_date = @nextReviewDate,
+         source_id = @sourceId
+       WHERE id = @id`,
+    ).run({
+      id,
+      docType: next.docType,
+      title: next.title,
+      versionLabel: next.versionLabel,
+      body: next.body,
+      state: next.state,
+      effectiveDate: next.effectiveDate,
+      nextReviewDate: next.nextReviewDate,
+      sourceId: next.sourceId,
+    });
+    const after = getDocumentOrThrow(db, id);
+    writeAudit(db, { action: 'update', entityType: DOCUMENT_ENTITY, entityId: id, before, after });
+    return after;
+  })();
+}
+
+function publishDocument(db: DB, id: number): DocumentVersion | null {
+  const before = getDocument(db, id);
+  if (!before) return null;
+  if (before.state === 'published') return before;
+
+  return db.transaction(() => {
+    const archived = archivePublishedForType(db, before.docType, id);
+    db.prepare("UPDATE document_versions SET state = 'published' WHERE id = ?").run(id);
+    const after = getDocumentOrThrow(db, id);
+    writeAudit(db, {
+      action: 'publish',
+      entityType: DOCUMENT_ENTITY,
+      entityId: id,
+      before: { target: before, archived },
+      after,
+    });
+    return after;
+  })();
+}
+
+function archivePublishedForType(db: DB, docType: DocumentType, exceptId?: number): DocumentVersion[] {
+  const published = db
+    .prepare(
+      `SELECT * FROM document_versions
+       WHERE doc_type = ? AND state = 'published' AND (? IS NULL OR id <> ?)
+       ORDER BY id ASC`,
+    )
+    .all(docType, exceptId ?? null, exceptId ?? null) as DocumentRow[];
+  if (published.length === 0) return [];
+  db.prepare(
+    `UPDATE document_versions
+     SET state = 'archived'
+     WHERE doc_type = ? AND state = 'published' AND (? IS NULL OR id <> ?)`,
+  ).run(docType, exceptId ?? null, exceptId ?? null);
+  return published.map(mapDocument);
+}
+
+function normalizeCreate(body: DocumentPayload): Omit<DocumentVersion, 'id' | 'createdAt'> {
+  return {
+    docType: parseDocumentType(body.docType),
+    title: parseRequiredString(body.title, 'title'),
+    versionLabel: parseRequiredString(body.versionLabel, 'versionLabel'),
+    body: parseRequiredString(body.body, 'body'),
+    state: body.state == null ? 'draft' : parseDocumentState(body.state),
+    effectiveDate: parseOptionalString(body.effectiveDate, 'effectiveDate'),
+    nextReviewDate: parseOptionalString(body.nextReviewDate, 'nextReviewDate'),
+    sourceId: parseOptionalString(body.sourceId, 'sourceId'),
+  };
+}
+
+function normalizeUpdate(body: DocumentPayload): Partial<Omit<DocumentVersion, 'id' | 'createdAt'>> {
+  const next: Partial<Omit<DocumentVersion, 'id' | 'createdAt'>> = {};
+  if (body.docType !== undefined) next.docType = parseDocumentType(body.docType);
+  if (body.title !== undefined) next.title = parseRequiredString(body.title, 'title');
+  if (body.versionLabel !== undefined) next.versionLabel = parseRequiredString(body.versionLabel, 'versionLabel');
+  if (body.body !== undefined) next.body = parseRequiredString(body.body, 'body');
+  if (body.state !== undefined) next.state = body.state == null ? 'draft' : parseDocumentState(body.state);
+  if (body.effectiveDate !== undefined) next.effectiveDate = parseOptionalString(body.effectiveDate, 'effectiveDate');
+  if (body.nextReviewDate !== undefined) next.nextReviewDate = parseOptionalString(body.nextReviewDate, 'nextReviewDate');
+  if (body.sourceId !== undefined) next.sourceId = parseOptionalString(body.sourceId, 'sourceId');
+  return next;
+}
+
+function mapDocument(row: DocumentRow): DocumentVersion {
+  return {
+    id: row.id,
+    docType: row.doc_type,
+    title: row.title,
+    versionLabel: row.version_label,
+    body: row.body,
+    state: row.state,
+    effectiveDate: row.effective_date,
+    nextReviewDate: row.next_review_date,
+    sourceId: row.source_id,
+    createdAt: row.created_at,
+  };
+}
+
+function parseId(id: string): number | null {
+  if (!/^\d+$/.test(id)) return null;
+  const parsed = Number(id);
+  return Number.isSafeInteger(parsed) && parsed > 0 ? parsed : null;
+}
+
+function parseDocumentType(value: unknown): DocumentType {
+  const docType = parseDocumentTypeOrNull(value);
+  if (!docType) throw new Error(`docType must be one of: ${DOCUMENT_TYPES.join(', ')}`);
+  return docType;
+}
+
+function parseDocumentTypeOrNull(value: unknown): DocumentType | null {
+  if (typeof value !== 'string') return null;
+  return DOCUMENT_TYPES.includes(value as DocumentType) ? (value as DocumentType) : null;
+}
+
+function parseDocumentState(value: unknown): DocumentState {
+  if (typeof value !== 'string' || !DOCUMENT_STATES.includes(value as DocumentState)) {
+    throw new Error(`state must be one of: ${DOCUMENT_STATES.join(', ')}`);
+  }
+  return value as DocumentState;
+}
+
+function parseRequiredString(value: unknown, field: string): string {
+  const text = parseOptionalString(value, field);
+  if (!text) throw new Error(`${field} is required`);
+  return text;
+}
+
+function parseOptionalString(value: unknown, field: string): string | null {
+  if (value == null) return null;
+  if (typeof value !== 'string') throw new Error(`${field} must be a string`);
+  const text = value.trim();
+  return text.length > 0 ? text : null;
+}
+
+function invalidPayload(error: unknown): { error: 'invalid_payload'; message: string } {
+  return { error: 'invalid_payload', message: error instanceof Error ? error.message : 'invalid payload' };
+}
